uint64_t PlanningParkingDebug::_computeHash(const __lcm_hash_ptr *p)
{
    const __lcm_hash_ptr *fp;
    for(fp = p; fp != NULL; fp = fp->parent)
        if(fp->v == PlanningParkingDebug::getHash)
            return 0;
    const __lcm_hash_ptr cp = { p, PlanningParkingDebug::getHash };

    uint64_t hash = 0xb1a2207dfa12fbc4LL +
         lcm_interface::Polygon2D::_computeHash(&cp) +
         lcm_interface::Polygon2D::_computeHash(&cp) +
         lcm_interface::PathPoint::_computeHash(&cp) +
         lcm_interface::Point2dList::_computeHash(&cp) +
         lcm_interface::TrajectoryPoint::_computeHash(&cp) +
         lcm_interface::TrajectoryPoint::_computeHash(&cp) +
         lcm_interface::TrajectoryPoint::_computeHash(&cp) +
         lcm_interface::Trajectory::_computeHash(&cp) +
         lcm_interface::Trajectory::_computeHash(&cp) +
         lcm_interface::Trajectory::_computeHash(&cp) +
         lcm_interface::Trajectory::_computeHash(&cp);

    return (hash<<1) + ((hash>>63)&1);
}

